form:Form.form:Scripts:
		var arrFILTER;
var arrMARK;

function ONLOAD()
{                  
	var t, ROW, VALUES;
	arrFILTER = new Array();

	//Valores Iniciales
	for (t=0; t<Ctrl("arrFILTER").CountRow(); t++)
	{
		ROW=Ctrl("arrFILTER").GetRow(t);
		VALUES=ROW.GetAttr("VALUES").split(",");
		for (d=0; d<VALUES.length; d++)
			if (VALUES[d]!="")
				arrFILTER.push(VALUES[d]);
	} 

 	//Actualizo la Lista
	refreshList();     
}

function load()    { NomadTimeout("internal_load();",100,"Cargando la Lista..."); }

function internal_load()
{   
    var auxArr;
	auxArr = exec_qry();
	if (auxArr==null) return;

	arrFILTER = auxArr; 
	refreshList();
}            

//Ejecuta el Query Seleccionado y devuelve un ARRAY con el resultado
function exec_qry()
{
	var np, nSQL, i;

	np = GetProxy();
	nSQL = np.SQLService(); 	         
	var qry = Ctrl("main").getResource("qry_liquidacion");
	var qryMembers = qry.split("##");   
	var qryMembers = qryMembers[1].split(",");  
	var nmdDATA=new NomadXML("PARAM"); 
	for (i=0; i<qryMembers.length; i++)
	{
		if (Ctrl(qryMembers[i]).m_Required && Ctrl(qryMembers[i]).GetXValue()=="")
		{
			alert("El valor es requerido");
			Ctrl(qryMembers[i]).SetFocus();
			return null;
		}				
		nmdDATA.SetAttr(qryMembers[i], Ctrl(qryMembers[i]).GetXValue());
	}                                      

  	var result = nSQL.GetXML(qry, nmdDATA.ToString());
  	var resultArray = XML2array(result);

 	return resultArray;  
}

//Actualiza la lista con el nuevo ARRAY
function refreshList()
{                          
 	var page=Ctrl("listFILTER").Page; 
	Ctrl("listFILTER").IDs=arrFILTER; 
	Ctrl("listFILTER").ResetSQL(); 
	Ctrl("listFILTER").GotoPage(page);

	Ctrl("filtrados").SetXValue("Liquidaciones Filtradas: "+arrFILTER.length);
}

function mark()
{
	NomadTimeout("internal_load_mark();",100,"Marcando en la Lista..."); 
}

//Marca en la lista las liquidaciones filtradas     
function internal_load_mark()
{
	var auxArr;
	auxArr = exec_qry();
	if (auxArr==null) return;

	arrMARK = auxArr; 

	for (n=0; n<arrMARK.length; n++)
	{    
		var X=arrMARK[n];
		for(i=0; i<arrFILTER.length; i++)
		{            
			if(arrFILTER[i]==X) 
			{
				if (Ctrl("arrcheckFILTER").GetRowByAttr("ID",X)==null) Ctrl("arrcheckFILTER").AddRow().SetAttr("ID",X);                                       
			  break;
			}
		} 
	} 
	refreshList();
}

//Agrega al Array A los elementos del Array B
function union(arrayA, arrayB)
{                    
	var t;
	var tmp=new Array();

	//Creo la HASH
	for (t=0; t<arrayA.length; t++) 
		tmp["K"+arrayA[t]]=1;

	//Agrego los que no estan	
	for (t=0; t<arrayB.length; t++) 
		if (tmp["K"+arrayB[t]]?false:true)
			arrayA.push(arrayB[t]);
}


//Elimina del Array A los elementos del Array B
function remove(arrayA, arrayB)
{
	var t;
	var tmp1=new Array();
	var tmp2=new Array();

	//Creo la HASH
	for (t=0; t<arrayB.length; t++) 
		tmp1["K"+arrayB[t]]=1;
	for (t=0; t<arrayA.length; t++) 
		tmp2.push(arrayA[t]);

	//Limpio el array
	arrayA.length=0;

	//Agrego los elemento NO comunes
	for (t=0; t<tmp2.length; t++)      
		if (tmp1["K"+tmp2[t]]?false:true)
			arrayA.push(tmp2[t]);
} 


//Elimina del Array A los elementos que no estan en el Array B
function intersect(arrayA, arrayB)
{
	var t;
	var tmp1=new Array();
	var tmp2=new Array();   

	//Creo la HASH
	for (t=0; t<arrayB.length; t++) 
		tmp1["K"+arrayB[t]]=1;
	for (t=0; t<arrayA.length; t++) 
		tmp2.push(arrayA[t]);

	//Limpio el array
	arrayA.length=0;

	//Agrego los elemento NO comunes
	for (t=0; t<tmp2.length; t++)      
		if (tmp1["K"+tmp2[t]]?true:false)
			arrayA.push(tmp2[t]);
}


//Elimina del Array A los elementos que no estan en el Array B
function copiar(arrayA, arrayB)
{
	//Limpio el array
	arrayA.length=0;

	//Agrego los elemento NO comunes
	for (var t=0; t<arrayB.length; t++)      
			arrayA.push(arrayB[t]);
}

//Transaforma un XML(tipo STRING) en ARRAY
function XML2array(xml)
{
	var arr = new Array();                        
	for (var cur=xml.FirstChild(); cur!=null; cur=cur.Next())
		arr.push(cur.GetAttr("id"));
	return arr;
}

//Function para activar y desactivar Botones
function enable_buttons()
{                       
	CtrlEnabled("listFILTER_Delete", Ctrl("arrcheckFILTER").CountRow()==0?false:true);
	CtrlEnabled("listFILTER_Clear" , true);

	enable_custom_buttons();
}

//Elimino iten del FILTRO
function delFILTER()
{                      
	for (var X=0; X<arrFILTER.length; X++)
	{
		if (Ctrl("arrcheckFILTER").GetRowByAttr("ID",arrFILTER[X])!=null)
		{                        
			arrFILTER.splice(X,1);
			X--;
		}
	}

	Ctrl("listFILTER").SetXValue("");
 	Ctrl("arrcheckFILTER").DelAllRow();
	refreshList();
}

//Limpio la Lista del FILTRO
function clearFILTER()
{  
	for (var X=0; X<arrFILTER.length; X++)
	{
		if (Ctrl("arrcheckFILTER").GetRowByAttr("ID",arrFILTER[X])==null)
		{                        
			arrFILTER.splice(X,1);
			X--;
		}
	}

	Ctrl("listFILTER").SetXValue("");
 	Ctrl("arrcheckFILTER").DelAllRow();
	refreshList();
}                 

function checkFILTER()
{          
	var X=Ctrl("listFILTER").GetXValue();   
	if (X!="" && Ctrl("listFILTER").LastColumnClick!="SEL")
	{                                                         
		if (Ctrl("arrcheckFILTER").GetRowByAttr("ID",X)==null) Ctrl("arrcheckFILTER").AddRow().SetAttr("ID",X);
		                                                  else Ctrl("arrcheckFILTER").DelRowByAttr("ID",X);    

		Ctrl("listFILTER").SetXValue("");
		refreshList();
	} 
}

//Deschequeo TOTAL
function unmarkFILTER()
{
	Ctrl("listFILTER").SetXValue("");
 	Ctrl("arrcheckFILTER").DelAllRow();
	refreshList();
}


function FillArray(numByRow)
{
	var t,n,values,sep,row,p;    
	var np, nSQL;

	np = GetProxy();
	nSQL = np.SQLService();

	//llamo al QUERY que ORDENA....	
 	if (Ctrl("main").getResource("qry_orderby"))
 	{

 		//Genero el XML de PARAMETROS.
 		var nmdDATA=new NomadXML("PARAM");
		values=""; sep="";
		for (t=0,n=0; t<arrFILTER.length; t++, n++)
		{
			if (n>=300)
			{              
				nmdDATA.AddTailElement("ROW").SetAttr("VALUES", values);
				values=""; sep=""; n=0;
			}                  
			values+=sep+arrFILTER[t];
			sep=",";
		}
		if (values!="") 
		{      
			nmdDATA.AddTailElement("ROW").SetAttr("VALUES", values);
		}



 		var qry = Ctrl("main").getResource("qry_orderby");
		var qryMembers = qry.split("##");

		if(qryMembers.length>1)
		{

			qryMembers = qryMembers[1].split(",");          		


			for (i=0; i<qryMembers.length; i++)
			{
				if (Ctrl(qryMembers[i]).m_Required && Ctrl(qryMembers[i]).GetXValue()=="")
				{
					alert("El valor es requerido");
					Ctrl(qryMembers[i]).SetFocus();
					return null;
				}				
				nmdDATA.SetAttr(qryMembers[i], Ctrl(qryMembers[i]).GetXValue());
			}
		}
  	var result = nSQL.GetXML(qry, nmdDATA.ToString());
	  arrFILTER = XML2array(result);
 	}

	//Genero el XML del IN
	Ctrl("arrFILTER").DelAllRow(); 

	values=""; sep="";
	for (t=0,n=0,p=0; t<arrFILTER.length; t++, n++)
	{
		if (n>=numByRow)
		{              
			p++;
			row=Ctrl("arrFILTER").AddRow()
			row.SetAttr("id", p);
			row.SetAttr("VALUES", values);
			values=""; sep=""; n=0;
		}                  

		values+=sep+arrFILTER[t];
		sep=",";
	}
	if (values!="") 
	{      
		p++;
		row=Ctrl("arrFILTER").AddRow()
		row.SetAttr("id", p);
		row.SetAttr("VALUES", values);
	}

}

function enable_custom_buttons()
{}                             

function Filtrar()
{   
	if (arrFILTER.length==0)
 	{             
 		alert("No hay liquidaciones filtradas.");
 		return false;
 	}
 	else if(arrFILTER.length>1)
 	{
 		alert("Debe seleccionar solo una liquidación.");
 		return false;
 	}                         

	FillArray(100);
	Ctrl("main").DoEvent("FILTER");
}
